/* Root design tokens */
:root {
  --color-primary-900: #111111;
  --color-primary-0: #ffffff;

  --color-secondary-pink: #C6284B;
  --color-secondary-dark: #303030;

  --color-accent-red: #E53958;
  --color-accent-green: #25D366;

  --color-neutral-1000: #000000;
  --color-neutral-100: #f5f5f5;
  --color-neutral-300: #dddddd;

  --color-success: #25D366;
  --color-error: #D32F2F;
  --color-warning: #FFA000;
  --color-info: #1976D2;

  --font-heading: "Space Grotesk", Helvetica, sans-serif;
  --font-body: "Source Sans 3", Arial, sans-serif;
  --font-code: "Source Code Pro", monospace;

  --font-size-h1: 36px;
  --font-size-h2: 30px;
  --font-size-h3: 24px;
  --font-size-body: 16px;
  --font-size-small: 14px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  --layout-max-width: 1200px;
}

/* Global resets */
*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-primary-900);
  background-color: var(--color-neutral-100);
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:focus-visible,
button:focus-visible {
  outline: 2px solid var(--color-accent-red);
  outline-offset: 2px;
}

/* Layout wrapper */
.site {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  background-color: var(--color-neutral-100);
}

/* Header */
.site-header {
  background-color: var(--color-primary-900);
  color: var(--color-primary-0);
}

.site-header__inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-4) var(--space-5);
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.site-brand {
  font-family: var(--font-heading);
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-weight: 500;
  font-size: 14px;
  line-height: var(--line-height-tight);
}

.site-brand__link {
  color: var(--color-primary-0);
}

.site-brand__line {
  display: block;
}

.primary-nav {
  font-family: var(--font-heading);
}

.primary-nav__list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-4);
  justify-content: flex-end;
}

.primary-nav__item {
}

.primary-nav__link {
  display: inline-block;
  padding: 4px 0;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-size: 13px;
  font-weight: 500;
  color: var(--color-primary-0);
  border-bottom: 2px solid transparent;
  transition: color 150ms ease-out, border-color 150ms ease-out;
}

.primary-nav__link:hover,
.primary-nav__link:focus-visible {
  color: var(--color-accent-red);
  border-bottom-color: var(--color-accent-red);
}

.primary-nav__link--active {
  color: var(--color-accent-red);
  border-bottom-color: var(--color-accent-red);
}

/* Main content */
.site-content {
  flex: 1 0 auto;
  background-color: var(--color-primary-0);
}

/* Footer */
.site-footer {
  background-color: var(--color-primary-900);
  color: var(--color-primary-0);
  margin-top: auto;
}

.site-footer__inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-6) var(--space-5) var(--space-4);
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-5);
  justify-content: space-between;
  border-top: 1px solid var(--color-secondary-dark);
}

.site-footer__brand {
  max-width: 320px;
}

.site-footer__title {
  font-family: var(--font-heading);
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-weight: 600;
  font-size: 14px;
  margin-bottom: var(--space-2);
}

.site-footer__text {
  margin: 0;
  font-size: var(--font-size-small);
  line-height: var(--line-height-relaxed);
  color: rgba(255, 255, 255, 0.72);
}

.site-footer__nav {
  flex: 1 1 360px;
}

.site-footer__list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
  gap: var(--space-2) var(--space-5);
}

.site-footer__item {
}

.site-footer__link {
  display: inline-block;
  font-family: var(--font-heading);
  text-transform: uppercase;
  letter-spacing: 0.14em;
  font-size: 12px;
  color: rgba(255, 255, 255, 0.82);
  transition: color 150ms ease-out;
}

.site-footer__link:hover,
.site-footer__link:focus-visible {
  color: var(--color-accent-red);
}

.site-footer__bottom {
  border-top: 1px solid var(--color-secondary-dark);
  margin-top: var(--space-3);
}

.site-footer__bottom-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-3) var(--space-5) var(--space-4);
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: var(--space-3);
}

.site-footer__copyright {
  margin: 0;
  font-size: 12px;
  color: rgba(255, 255, 255, 0.6);
}

/* Typography helpers */
h1,
h2,
h3,
h4 {
  font-family: var(--font-heading);
  text-transform: none;
  margin-top: 0;
  color: var(--color-primary-900);
}

h1 {
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
}

h2 {
  font-size: var(--font-size-h2);
  line-height: var(--line-height-tight);
}

h3 {
  font-size: var(--font-size-h3);
  line-height: var(--line-height-tight);
}

p {
  margin-top: 0;
  margin-bottom: var(--space-3);
}

/* Generic hero pattern (optional, for page templates) */
.hero {
  position: relative;
  color: var(--color-primary-0);
  min-height: 320px;
  background-color: #000;
  background-position: center;
  background-size: cover;
  background-repeat: no-repeat;
}

.hero::before {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(to bottom, rgba(0,0,0,0.55), rgba(0,0,0,0.35));
}

.hero__inner {
  position: relative;
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-6) var(--space-5);
}

.hero__title {
  font-family: var(--font-heading);
  font-size: 32px;
  line-height: var(--line-height-tight);
  font-weight: 400;
}

.hero__accent-line {
  width: 72px;
  height: 2px;
  background-color: var(--color-accent-red);
  margin-top: var(--space-3);
}

/* Responsive tweaks */
@media (max-width: 768px) {
  .site-header__inner {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-3);
  }

  .primary-nav__list {
    justify-content: flex-start;
  }

  .site-footer__inner {
    padding-inline: var(--space-3);
  }

  .site-footer__bottom-inner {
    padding-inline: var(--space-3);
    flex-direction: column;
    align-items: flex-start;
  }
}
